module top_module(in, s, out);input wire[3: 0] in;
	input wire[1: 0] s;
	output wire out;
	reg obf__out;
	always @(in or s)
		case (s)
			2'b00: obf__out = in[0];
			2'b01: obf__out = in[1];
			2'b10: obf__out = in[2];
			2'b11: obf__out = in[3];
			default: obf__out = 1'b0;
		endcase
	assign out = obf__out;
endmodule
